SELECT bs."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(MAP(ARRAY['FullServiceRestaurant', 'QuickServiceRestaurant', 'RetailStandalone', 'RetailStripmall', 'PrimarySchool', 'SecondarySchool', 'SmallOffice', 'MediumOffice', 'LargeOffice', 'SmallHotel', 'LargeHotel', 'Hospital', 'Outpatient', 'Warehouse'], ARRAY[1.0, 0.8, 0.6, 0.5, 0.7, 0.7, 0.4, 0.6, 0.9, 0.5, 0.8, 1.0, 0.7, 0.3])[bs."in.comstock_building_type"] * bs.weight) AS bldg_load_factor FROM comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs.state = 'CO' GROUP BY 1 ORDER BY 1